# Problem: Implement two rate limiting algorithms (Token Bucket & Sliding Window)
# plus a middleware combiner, key extractors, and a factory function.
#
# Approach:
# - Token Bucket: Each key tracks (tokens, last_refill_time). On consume,
#   refill tokens based on elapsed time, then try to deduct requested tokens.
# - Sliding Window Log: Each key tracks a list of request timestamps. On check,
#   prune expired entries, then compare count against max_requests.
# - Middleware: Check all limiters; return first denial or lowest remaining.
#
# Time complexity: Token Bucket O(1) per call; Sliding Window O(n) per call
#   where n is number of requests in the window.
# Space complexity: O(k) for Token Bucket (k=keys); O(k*n) for Sliding Window.
#
# Key steps:
# 1. Implement RateLimitResult as a Pydantic model
# 2. Implement TokenBucketLimiter with per-key state and time-based refill
# 3. Implement SlidingWindowLimiter with per-key timestamp logs
# 4. Implement RateLimiterMiddleware to combine limiters
# 5. Implement key extractors and factory function

import time
from typing import Any
from pydantic import BaseModel


class RateLimitResult(BaseModel):
    allowed: bool
    remaining: int
    retry_after: float | None = None
    limit: int
    window: float


class TokenBucketLimiter:

    def __init__(self, capacity: int, refill_rate: float):
        self.capacity = capacity
        self.refill_rate = refill_rate
        # Per-key state: {key: (current_tokens, last_refill_time)}
        self._buckets: dict[str, tuple[float, float]] = {}

    def consume(self, key: str, tokens: int = 1) -> RateLimitResult:
        now = time.time()

        if key not in self._buckets:
            # Start with a full bucket on first access
            self._buckets[key] = (float(self.capacity), now)

        current_tokens, last_time = self._buckets[key]

        # Refill based on elapsed time, capped at capacity
        elapsed = now - last_time
        current_tokens = min(self.capacity, current_tokens + elapsed * self.refill_rate)

        if current_tokens >= tokens:
            current_tokens -= tokens
            self._buckets[key] = (current_tokens, now)
            return RateLimitResult(
                allowed=True,
                remaining=int(current_tokens),
                retry_after=None,
                limit=self.capacity,
                window=self.capacity / self.refill_rate,  # time to fill entire bucket
            )
        else:
            # Calculate how long until enough tokens accumulate
            deficit = tokens - current_tokens
            retry_after = deficit / self.refill_rate
            self._buckets[key] = (current_tokens, now)
            return RateLimitResult(
                allowed=False,
                remaining=int(current_tokens),
                retry_after=retry_after,
                limit=self.capacity,
                window=self.capacity / self.refill_rate,
            )


class SlidingWindowLimiter:

    def __init__(self, max_requests: int, window_seconds: float):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        # Per-key state: {key: [timestamp, timestamp, ...]}
        self._logs: dict[str, list[float]] = {}

    def check(self, key: str) -> RateLimitResult:
        now = time.time()
        cutoff = now - self.window_seconds

        if key not in self._logs:
            self._logs[key] = []

        # Remove timestamps older than the window
        self._logs[key] = [t for t in self._logs[key] if t > cutoff]

        # Record current request
        self._logs[key].append(now)

        count = len(self._logs[key])

        if count <= self.max_requests:
            return RateLimitResult(
                allowed=True,
                remaining=self.max_requests - count,
                retry_after=None,
                limit=self.max_requests,
                window=self.window_seconds,
            )
        else:
            # Oldest timestamp determines when the window will slide enough
            oldest = self._logs[key][0]
            retry_after = oldest + self.window_seconds - now
            return RateLimitResult(
                allowed=False,
                remaining=0,
                retry_after=retry_after,
                limit=self.max_requests,
                window=self.window_seconds,
            )


class RateLimiterMiddleware:

    def __init__(self, limiters: list):
        self.limiters = limiters

    def check(self, key: str) -> RateLimitResult:
        results = []
        for limiter in self.limiters:
            # Each limiter exposes either consume() or check()
            if hasattr(limiter, 'consume'):
                result = limiter.consume(key)
            else:
                result = limiter.check(key)

            # Return immediately on first denial
            if not result.allowed:
                return result
            results.append(result)

        # All passed — return the one with the lowest remaining count
        return min(results, key=lambda r: r.remaining)


class IPBasedKey:
    @staticmethod
    def extract(request_data: dict) -> str:
        return request_data.get('ip', 'unknown')


class UserBasedKey:
    @staticmethod
    def extract(request_data: dict) -> str:
        return request_data.get('user_id', 'anonymous')


def build_api_limiter() -> RateLimiterMiddleware:
    token_bucket = TokenBucketLimiter(capacity=10, refill_rate=2.0)
    sliding_window = SlidingWindowLimiter(max_requests=100, window_seconds=60.0)
    return RateLimiterMiddleware(limiters=[token_bucket, sliding_window])
